INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '1fd0bd77-bd0f-4efe-897f-34c72c6eb81e',
  '00000000-0000-0000-0000-000000000001',
  $escape$ESP32 — Optimizing Arduino Setup/Loop with Serial Communication$escape$,
  $escape$The ESP32's Arduino setup() function runs once at startup, while loop() runs continuously. In serial communication, choose between hardwareSerial and SoftwareSerial libraries. SoftwareSerial is slower and more prone to errors, but useful for multiple serial connections.$escape$,
  $escape$const char* ssid = "your_wifi_ssid"; const char* password = "your_wifi_password"; void setup() { Serial.begin(115200); } void loop() { Serial.println("Hello World"); delay(1000); }$escape$,
  $escape$cpp$escape$,
